function solve(nums, target) {
    const n = nums.length;

    // We want to find a subset of nums whose XOR sum is target,
    // and maximize the size of this subset (which minimizes removals).
    // The number of removals is n - max_subset_size.

    // Since n is small (up to 40), we can use meet-in-the-middle.

    const m = Math.floor(n / 2);
    const leftNums = nums.slice(0, m);
    const rightNums = nums.slice(m);

    // Step 1: Generate all possible XOR sums for the left half.
    // Store them as Map<XOR_sum, max_size> where max_size is the size of the subset that yields XOR_sum.
    const leftSums = new Map();
    leftSums.set(0, 0); // Empty set has XOR sum 0 and size 0

    for (const num of leftNums) {
        const newSums = new Map();
        for (const [xorSum, size] of leftSums.entries()) {
            const newXorSum = xorSum ^ num;
            const newSize = size + 1;

            // Update the map: if we already have this xorSum, we only keep the one with the larger size.
            const existingSize = leftSums.get(newXorSum) || 0;
            if (newSize > existingSize) {
                newSums.set(newXorSum, newSize);
            }
        }
        // Merge newSums into leftSums, keeping the maximum size for each XOR sum
        for (const [xorSum, size] of newSums.entries()) {
            const existingSize = leftSums.get(xorSum) || 0;
            if (size > existingSize) {
                leftSums.set(xorSum, size);
            }
        }
    }

    // Step 2: Generate all possible XOR sums for the right half,
    // and simultaneously check for the target.
    let maxSubsetSize = -1;

    // Store right sums and their max sizes similarly for completeness, 
    // though we can combine the check into the iteration for space efficiency.
    const rightSums = new Map();
    rightSums.set(0, 0); // Empty set has XOR sum 0 and size 0

    // Initialize maxSubsetSize with the case where the whole array XORs to target (if it's achievable by one half)
    if (leftSums.has(target)) {
        maxSubsetSize = Math.max(maxSubsetSize, leftSums.get(target));
    }


    for (const num of rightNums) {
        const newSums = new Map();
        for (const [xorSum, size] of rightSums.entries()) {
            const newXorSum = xorSum ^ num;
            const newSize = size + 1;

            // Check for the required complement in leftSums
            // We need leftXOR ^ rightXOR = target, so leftXOR = target ^ rightXOR
            const requiredLeftXOR = target ^ newXorSum;
            if (leftSums.has(requiredLeftXOR)) {
                const leftSize = leftSums.get(requiredLeftXOR);
                const totalSize = leftSize + newSize;
                maxSubsetSize = Math.max(maxSubsetSize, totalSize);
            }

            // Update rightSums map
            const existingSize = rightSums.get(newXorSum) || 0;
            if (newSize > existingSize) {
                newSums.set(newXorSum, newSize);
            }
        }

        // Merge newSums into rightSums
        for (const [xorSum, size] of newSums.entries()) {
            const existingSize = rightSums.get(xorSum) || 0;
            if (size > existingSize) {
                rightSums.set(xorSum, size);
            }
        }
    }

    // Final check: We must also check the case where the target is achieved entirely within the right half.
    for (const [xorSum, size] of rightSums.entries()) {
        if (xorSum === target) {
            maxSubsetSize = Math.max(maxSubsetSize, size);
        }
    }


    if (maxSubsetSize === -1) {
        return -1;
    }

    return n - maxSubsetSize;
}

