        val newSize = size + 1

        // Check for complement in leftSums: leftXOR = target ^ newXorSum
        val requiredLeftXOR = target xor newXorSum
        if (leftSums.contains(requiredLeftXOR)) {
          val leftSize = leftSums(requiredLeftXOR)
          val totalSize = leftSize + newSize
          maxSubsetSize = maxSubsetSize.max(totalSize)
        }

        // Update rightSums map (logic similar to leftSums generation)
        val existingSizeInNewSums = newSums.getOrElse(newXorSum, -1)
        if (newSize > existingSizeInNewSums) {
          newSums.put(newXorSum, newSize)
        }
        val existingSizeInRightSums = rightSums.getOrElse(newXorSum, -1)
        if (newSize > existingSizeInRightSums) {
          newSums.put(newXorSum, newSize)
        }
      }

      // Merge newSums into rightSums
      for ((xorSum, size) <- newSums) {
        val existingSize = rightSums.getOrElse(xorSum, -1)
        if (size > existingSize) {
          rightSums.update(xorSum, size)
        }
      }
    }

    // Final check: Target achieved entirely within the right half
